import javax.crypto.Cipher;
import java.util.Base64;

public final class SecretCodec {

    private final Cipher encryptCipher;
    private final Cipher decryptCipher;

    public SecretCodec(Cipher encryptCipher, Cipher decryptCipher) {
        this.encryptCipher = encryptCipher;
        this.decryptCipher = decryptCipher;
    }

    public String encrypt(String plain) throws Exception {
        byte[] enc = encryptCipher.doFinal(plain.getBytes());
        return Base64.getEncoder().encodeToString(enc);
    }

    public String decrypt(String token) throws Exception {
        byte[] raw = Base64.getDecoder().decode(token);
        byte[] dec = decryptCipher.doFinal(raw);
        return new String(dec);
    }
}
